          final metadata = _extractMetadata(assetDetails);
          movies.add(Movie(
            title: metadata['title']!,
            description: metadata['description']!,
            playbackId: playbackId,
            rating: 4.5,
            genres: ['Mux', 'API'],
            imageUrl:
