      for (var assetDetails in detailedAssets) {
        if (assetDetails == null) continue;
        if (assetDetails['status'] != 'ready') continue;

        final playbackIds = assetDetails['playback_ids'] as List?;
        if (playbackIds != null && playbackIds.isNotEmpty) {
