              Icon(Icons.videocam_off, size: 60, color: theme.disabledColor),
              const SizedBox(height: 16),
              Text("No videos found",
                  style: TextStyle(color: theme.disabledColor)),
            ],
          ),
        ),
      );
    }

    // Основной контент
    return Scaffold(
      extendBodyBehindAppBar: true,
      body: RefreshIndicator(
        onRefresh: () => ref.read(shortVideosProvider.notifier).refresh(),
        color: theme.colorScheme.onSurface,
        backgroundColor: theme.colorScheme.primary,
        child: Stack(
          children: [
            PageView.builder(
              controller: _pageController,
              scrollDirection: Axis.vertical,
              itemCount: filteredVideos.length,
              onPageChanged: _onPageChanged,
              itemBuilder: (context, index) {
                return ShortPlayerScreen(
                  key: ValueKey(filteredVideos[index].playbackId),
                  movie: filteredVideos[index],
                  index: index,
                  isCurrent: index == _currentIndex,
                  onVideoFinished: () {
                    if (index < filteredVideos.length - 1) {
                      _pageController.nextPage(
                        duration: const Duration(milliseconds: 300),
                        curve: Curves.easeInOut,
                      );
                    }
                  },
                );
              },
            ),
            _buildTopBar(context, ref),
          ],
        ),
      ),
    );
  }

  Widget _buildTopBar(BuildContext context, WidgetRef ref) {
    final showFilters = ref.watch(filterVisibilityProvider);
    final selectedGenre = ref.watch(selectedGenreProvider);
    final genres = ref.watch(availableGenresProvider);
    final theme = Theme.of(context);

    final overlayColor = theme.colorScheme.surface.withOpacity(0.6);
    final iconColor = theme.colorScheme.onSurface;

    return Align(
      alignment: Alignment.topCenter,
      child: SafeArea(
        child: Padding(
          padding: const EdgeInsets.only(top: 8.0, left: 16.0),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  Container(
                    decoration: BoxDecoration(
                        color: overlayColor,
                        borderRadius: BorderRadius.circular(8)),
                    child: IconButton(
                        tooltip: "Filters",
                        icon: Icon(Icons.menu, color: iconColor),
                        onPressed: () => ref
                            .read(filterVisibilityProvider.notifier)
                            .state = !showFilters),
                  ),
                  const SizedBox(height: 12),
                  Container(
                    decoration: BoxDecoration(
                        color: overlayColor,
                        borderRadius: BorderRadius.circular(8)),
                    child: IconButton(
                      tooltip: "Settings",
                      icon: Icon(Icons.settings, color: iconColor),
                      onPressed: () => Navigator.push(
                          context,
                          MaterialPageRoute(
                              builder: (_) => const SettingsScreen())),
                    ),
                  ),
                ],
              ),
              const SizedBox(width: 12),
              Expanded(
                child: AnimatedSize(
                  duration: const Duration(milliseconds: 300),
                  curve: Curves.easeInOut,
                  child: showFilters
                      ? SingleChildScrollView(
                          scrollDirection: Axis.horizontal,
                          child: Row(
                              children: genres
                                  .map((g) => GenreFilterChip(
                                      genre: g,
                                      isSelected: selectedGenre == g,
                                      onSelected: (val) => ref
                                          .read(selectedGenreProvider.notifier)
                                          .state = g))
                                  .toList()))
                      : const SizedBox.shrink(),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class GenreFilterChip extends StatelessWidget {
  final String genre;
  final bool isSelected;
  final Function(bool) onSelected;

  const GenreFilterChip(
      {super.key,
      required this.genre,
      required this.isSelected,
      required this.onSelected});

  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 4.0),
      child: ChoiceChip(
        label: Text(genre),
        selected: isSelected,
        onSelected: onSelected,
      ),
